import com.meltwater.wrapidity.service.groot.core.token.Token;
import com.meltwater.wrapidity.service.groot.core.token.TokenTable;
import lombok.AllArgsConstructor;

import java.util.Comparator;

@AllArgsConstructor
public class LandmarkCandidateComparator implements Comparator<Token> {

	private final TokenTable table;

	@Override
	public int compare(Token t1, Token t2) {
		int cmp = this.compareOccVectorsSupport(t1, t2);

		if (cmp == 0) {
			cmp = this.compareTokenTypes(t1, t2);
		}

		/* prefer lower index */
		if (cmp == 0) {
			cmp = Integer.compare(t2.getPreOrderIndex(), t1.getPreOrderIndex());
		}
		/* tie-breaker */
		if (cmp == 0) {
			cmp = Integer.compare(System.identityHashCode(t1), System.identityHashCode(t2));
		}

		return cmp;
	}

	private int compareOccVectorsSupport(Token t1, Token t2) {
		final OccurrencesVector ov1 = this.table.getOccVector(t1);
		final OccurrencesVector ov2 = this.table.getOccVector(t2);

		/* prefer binary occurrence vectors */
		// See also Landmarker.isSuitableLandmark()
		boolean b1 = ov1.isBinary();
		boolean b2 = ov2.isBinary();
		if (b1 != b2) {
			return b1 ? +1 : -1;
		}

		/* tokens that appear the most are preferred */
		return Integer.compare(ov1.getSupport(), ov2.getSupport());
	}

